mapper.sql:


where 1 = 1




  and fdqgd.group_id = #{criteria.groupId,jdbcType=BIGINT}




  and fdqgd.group_id in (
       SELECT fdqg.id
         FROM fnd_dynamic_query_group fdqg
        WHERE fdqg.name = #{criteria.groupName,jdbcType=VARCHAR}
          AND fdqg.enabled_flag = 1)




  and fdqgd.enabled_flag = #{criteria.enabled,jdbcType=BIT}




  and (fdqgd.label like #{criteria.blurry,jdbcType=VARCHAR}
     or fdqgd.field like #{criteria.blurry,jdbcType=VARCHAR})
